  epsilonSpent: number;
  deltaSpent: number;
  roundsParticipated: number;
  gradientsContributed: number;
  lastUpdated: number;
}

/**
 * Federation configuration
 */
export interface FederationConfig {
  // Colony management
  maxColonies: number;
